 * Uses git -c safe.directory=/vault since the task runner doesn't
 * inherit the container's GIT_CONFIG_GLOBAL env var.
 */
const { execSync } = require('child_process');
const GIT = 'git -c safe.directory=/vault';

// Stash uncommitted changes to prevent pull conflicts
let hasStash = false;
try {
  execSync(`cd /vault && ${GIT} add -A`, { encoding: 'utf-8', timeout: 5000 });
  const out = execSync(`cd /vault && ${GIT} stash`, { encoding: 'utf-8', timeout: 5000 });
  hasStash = !out.includes('No local changes');
} catch (e) { /* nothing to stash */ }

try {
  execSync(`cd /vault && ${GIT} pull --ff-only`, { encoding: 'utf-8', timeout: 15000 });
} catch (err) {
  try {
    execSync(`cd /vault && ${GIT} pull --rebase`, { encoding: 'utf-8', timeout: 15000 });
  } catch (e2) {
    if (hasStash) try { execSync(`cd /vault && ${GIT} stash pop`, { encoding: 'utf-8' }); } catch(e) {}
    throw new Error('Git pull failed: ' + e2.message);
  }
}

if (hasStash) {
  try { execSync(`cd /vault && ${GIT} stash pop`, { encoding: 'utf-8', timeout: 5000 }); } catch(e) {}
}

