 *   - Items are ordered: DELETEs before INSERTs per file.
 *     The downstream PostgreSQL node processes items sequentially,
 *     so deletes complete before inserts for the same file_path.
 *   - SQL is pre-built here (with proper escaping) rather than using
 *     n8n expression interpolation, which is fragile with special chars.
 *   - TEI is called in batches of 8 (max_batch_requests).
 *   - spawn('wget') used instead of execFileSync to avoid blocking
 *     the event loop and causing task runner heartbeat failures.
 */
const { execFileSync, spawn } = require('child_process');
const fs = require('fs');
const path = require('path');

// ─── Configuration ───────────────────────────────────────────
const VAULT_PATH = '/vault';
const TEI_URL = 'http://text-embeddings:80/v1/embeddings';
const TEI_MODEL = 'pplx-embed-context-v1-0.6b';
const TEI_BATCH_SIZE = 8;

const EXCLUDE_PREFIXES = [
  'system/', '.obsidian/', 'assets/', '.git/',
  '80-PERSONAL/84-Private/', '14-Operations/Legal/clients/'
];
const SKIP_AUTHORS = ['n8n-vault', 'vault-embedding', 'n8n'];

const MAX_CHUNK_CHARS = 2500;
const OVERLAP_CHARS = 200;
const MIN_CHUNK_CHARS = 50;
const MIN_FILE_CHARS = 100;

// ─── HTTP POST via wget (async, non-blocking) ────────────────
function httpPost(url, bodyObj) {
  return new Promise((resolve, reject) => {
    const id = Date.now() + '-' + Math.random().toString(36).slice(2, 8);
    const tmpIn = `/tmp/embed-req-${id}.json`;
    const tmpOut = `/tmp/embed-res-${id}.json`;
    fs.writeFileSync(tmpIn, JSON.stringify(bodyObj));

    const proc = spawn('wget', [
      '-q', '-O', tmpOut,
      '--header=Content-Type: application/json',
      `--post-file=${tmpIn}`,
      '--timeout=60',
      url
    ]);

    let stderr = '';
    proc.stderr.on('data', d => stderr += d.toString());

    proc.on('close', code => {
      try { fs.unlinkSync(tmpIn); } catch(e) {}
      if (code !== 0) {
        try { fs.unlinkSync(tmpOut); } catch(e) {}
        return reject(new Error(`wget exit ${code}: ${stderr}`));
      }
      try {
        const res = JSON.parse(fs.readFileSync(tmpOut, 'utf-8'));
        fs.unlinkSync(tmpOut);
        resolve(res);
      } catch(e) {
        try { fs.unlinkSync(tmpOut); } catch(e2) {}
        reject(new Error('TEI parse error: ' + e.message));
      }
    });
    proc.on('error', err => {
      try { fs.unlinkSync(tmpIn); } catch(e) {}
      reject(err);
    });
  });
}

