    for (const f of (c.removed||[])) { if (f.endsWith('.md') && !EXCLUDE_PREFIXES.some(p=>f.startsWith(p))) { addMod.delete(f); rem.add(f); } }
  }

  if (!addMod.size && !rem.size)
