      const meta = {
        type: metadata.type || 'unknown',
        tags: Array.isArray(metadata.tags) ? metadata.tags : [],
        created: metadata.created || null,
        updated: metadata.updated || null,
        source: metadata.source || null,
        vault_path: fp,
        title
      };

      const chunks = chunkByHeadings(bodyText, title);
      if (!chunks.length) { stats.files_skipped++; continue; }

      const embeddings = await embedAllChunks(chunks);

      // DELETE old chunks first
      items.push({ json: { query: `DELETE FROM vault_embeddings WHERE file_path = ${pgStr(fp)};` } });

      // INSERT new chunks
      for (let i = 0; i < chunks.length; i++) {
        const ch = chunks[i];
        const embStr = '[' + embeddings[i].join(',') + ']';
        items.push({ json: {
          query: `INSERT INTO vault_embeddings (file_path, chunk_index, heading, content, embedding, metadata, file_hash, updated_at) VALUES (${pgStr(fp)}, ${ch.chunk_index}, ${ch.heading !== null ? pgStr(ch.heading) : 'NULL'}, ${pgStr(ch.content)}, '${embStr}'::vector, ${pgStr(JSON.stringify(meta))}::jsonb, ${pgStr(fileHash)}, NOW());`
        } });
        stats.total_chunks++;
      }
      stats.files_processed++;
    } catch (e) {
      stats.errors.push(fp + ': ' + e.message);
    }
  }

  // Append summary as last item
  items.push({ json: { _isSummary: true, status: 'ok', ...stats } });
  return items;
}

return await main();

